namespace BlazorApp.Services;

public class Notification
{
    public int Id { get; set; }
    public string Message { get; set; } = string.Empty;
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 4;
    private readonly List<Notification> _notifications = new()
    {
        new() { Id = 1, Message = "Welcome to the app!", Timestamp = DateTime.Now.AddMinutes(-30) },
        new() { Id = 2, Message = "Your profile was updated.", Timestamp = DateTime.Now.AddMinutes(-15) },
        new() { Id = 3, Message = "New feature available: dark mode.", Timestamp = DateTime.Now.AddMinutes(-5) },
    };

    private static readonly string[] SampleMessages =
    [
        "You have a new follower.",
        "Your report is ready to download.",
        "Scheduled maintenance tonight at 11 PM.",
        "Your subscription renews tomorrow.",
        "A teammate commented on your post.",
        "Security alert: new login detected.",
    ];

    public Task<List<Notification>> GetNotificationsAsync()
    {
        lock (_notifications)
        {
            return Task.FromResult(_notifications.ToList());
        }
    }

    public Task<List<Notification>> GetNotificationsSinceAsync(int lastId)
    {
        // Simulate new notifications arriving occasionally
        lock (_notifications)
        {
            if (Random.Shared.Next(3) == 0) // ~33% chance each poll
            {
                var msg = SampleMessages[Random.Shared.Next(SampleMessages.Length)];
                _notifications.Add(new Notification
                {
                    Id = _nextId++,
                    Message = msg,
                    Timestamp = DateTime.Now,
                });
            }

            var newer = _notifications.Where(n => n.Id > lastId).ToList();
            return Task.FromResult(newer);
        }
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using BlazorApp.Services
@inject NotificationService NotificationSvc
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    @if (NotificationList is not null)
    {
        <span class="badge bg-primary ms-2">@NotificationList.Count</span>
    }
</h1>

@if (NotificationList is null)
{
    <p><em>Loading...</em></p>
}
else if (NotificationList.Count == 0)
{
    <p>No notifications.</p>
}
else
{
    <ul class="list-group">
        @foreach (var n in NotificationList.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item">
                <strong>@n.Message</strong>
                <small class="text-muted ms-2">@n.Timestamp.ToString("g")</small>
            </li>
        }
    </ul>
}

@code {
    private CancellationTokenSource? _cts;

    [PersistentState]
    public List<Notification>? NotificationList { get; set; }

    protected override async Task OnInitializedAsync()
    {
        // Only fetch if not restored from prerender state
        NotificationList ??= await NotificationSvc.GetNotificationsAsync();
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender never runs during prerender — safe to start polling
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct).ConfigureAwait(false);

            if (ct.IsCancellationRequested) break;

            var lastId = NotificationList?.MaxBy(n => n.Id)?.Id ?? 0;
            var newer = await NotificationSvc.GetNotificationsSinceAsync(lastId);

            if (newer.Count > 0)
            {
                NotificationList ??= new();
                NotificationList.AddRange(newer);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

